'use client';

import { useState } from 'react';
import styles from './page.module.css';

export default function Home() {
  const [selectedFile, setSelectedFile] = useState(null);
  const [fileName, setFileName] = useState('');
  const [uploading, setUploading] = useState(false);
  const [uploadStatus, setUploadStatus] = useState('');

  const handleFileSelect = (event) => {
    const file = event.target.files[0];
    if (file) {
      setSelectedFile(file);
      setFileName(file.name);
      setUploadStatus('');
    }
  };

  const handleUploadClick = async () => {
    if (!selectedFile) {
      alert('Please select a file first');
      return;
    }

    setUploading(true);
    setUploadStatus('Uploading...');

    try {
      const formData = new FormData();
      formData.append('image', selectedFile);

      const response = await fetch('http://localhost:5000/api/upload', {
        method: 'POST',
        body: formData,
      });

      const data = await response.json();

      if (data.success) {
        setUploadStatus(`✅ Success! File uploaded: ${data.filename}`);
        console.log('Upload successful:', data);
        alert(`File uploaded successfully!\nFilename: ${data.filename}`);
      } else {
        setUploadStatus(`❌ Error: ${data.error}`);
        console.error('Upload failed:', data.error);
        alert(`Upload failed: ${data.error}`);
      }
    } catch (error) {
      setUploadStatus(`❌ Error: ${error.message}`);
      console.error('Upload error:', error);
      alert(`Upload error: ${error.message}`);
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className={styles.container}>
      <main className={styles.main}>
        <h1 className={styles.title}>Inventory Upload</h1>
        
        <div className={styles.uploadSection}>
          <div className={styles.fileInputWrapper}>
            <input
              type="file"
              id="fileInput"
              accept="image/*"
              onChange={handleFileSelect}
              className={styles.fileInput}
              disabled={uploading}
            />
            <label htmlFor="fileInput" className={styles.fileLabel}>
              {fileName || 'Choose an image file'}
            </label>
          </div>

          {selectedFile && (
            <div className={styles.fileInfo}>
              <p>Selected: {selectedFile.name}</p>
              <p>Size: {(selectedFile.size / 1024).toFixed(2)} KB</p>
            </div>
          )}

          <button 
            onClick={handleUploadClick}
            className={styles.uploadButton}
            disabled={!selectedFile || uploading}
          >
            {uploading ? 'Uploading...' : 'Upload Image'}
          </button>

          {uploadStatus && (
            <div className={uploadStatus.includes('✅') ? styles.successStatus : styles.errorStatus}>
              <p>{uploadStatus}</p>
            </div>
          )}
        </div>

        <div className={styles.status}>
          <p>Status: Ready</p>
        </div>
      </main>
    </div>
  );
}